import { Injectable, Logger } from '@nestjs/common';
import {
    Counter,
    Histogram,
    Registry,
    collectDefaultMetrics,
} from 'prom-client';
import { InjectMetric } from '@willsoto/nestjs-prometheus';

@Injectable()
export class PrometheusService {
    private readonly logger = new Logger(PrometheusService.name);

    constructor() {
        collectDefaultMetrics();
    }


    public createCounter(name: string, help: string, labelNames?: string[]): Counter {
        return new Counter({ name, help, labelNames });
    }

    public createHistogram(name: string, help: string, labelNames: string[], buckets: number[]): Histogram {
        return new Histogram({ name, help, labelNames, buckets });
    }

    public getMetrics(): Promise<string> {
        return Registry.defaultRegistry.metrics();
    }
}
