// src/auth/agent.auth.guard.ts
import { Injectable, CanActivate, ExecutionContext, UnauthorizedException } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { AgentJwtPayload } from '../types/AgentJwtPayload';

export const AgentPermissions = (...permissions: string[]) => Reflector.createDecorator<string[]>(permissions);

@Injectable()
export class AgentAuthGuard implements CanActivate {
    constructor(private reflector: Reflector) {}

    canActivate(context: ExecutionContext): boolean {
        const requiredPermissions = this.reflector.get(AgentPermissions, context.getHandler());

        if (!requiredPermissions) {
            // If no specific permissions are required, allow access
            return true;
        }

        const request = context.switchToHttp().getRequest();
        const agent: AgentJwtPayload = request.user;

        if (!agent) {
            throw new UnauthorizedException('Agent not authenticated');
        }

        const hasPermission = requiredPermissions.every(permission => agent.permissions.includes(permission));

        if (!hasPermission) {
            throw new UnauthorizedException('Agent does not have required permissions');
        }

        return true;
    }
}
