import { Injectable, Inject, Logger } from '@nestjs/common';
import * as fs from 'fs';
import * as path from 'path';
import { AgentCard, AgentCardSchema, AgentCardSchemaGuard } from '../types/AgentCard';
import { ConfigService } from '@nestjs/config';
import { ZodSchema } from 'zod';

@Injectable()
export class AgentInfoService {
    private agentCards: Map<string, AgentCard> = new Map();

    constructor(
        @Inject('LOGGER') private logger: Logger,
        private configService: ConfigService, // Inject ConfigService
    ) {
        this.loadAgentCards();
    }

    private async loadAgentCards(): Promise<void> {
        const agentCardDir = this.configService.get<string>('AGENT_CARD_DIRECTORY') || path.join(__dirname, '../../agent-cards'); // Get from config
        try {
            const files = await fs.promises.readdir(agentCardDir);
            for (const file of files) {
                if (file.endsWith('.json')) {
                    const filePath = path.join(agentCardDir, file);
                    try {
                        const card = JSON.parse(await fs.promises.readFile(filePath, 'utf-8'));
                        if (AgentCardSchemaGuard(card)) {
                            this.agentCards.set(card.id, card);
                            this.logger.log(`Loaded AgentCard for ${card.id} from ${filePath}`);
                        } else {
                            this.logger.error(`Invalid AgentCard format in ${filePath}:`, AgentCardSchema.safeParse(card).error);
                        }
                    } catch (parseError) {
                        this.logger.error(`Error parsing AgentCard in ${filePath}:`, parseError);
                    }
                }
            }
        } catch (error) {
            this.logger.error('Error loading AgentCards:', error);
        }
    }


    async getAgentCard(agentId: string): Promise<AgentCard | undefined> {
        return this.agentCards.get(agentId);
    }

