    async addOrUpdateAgentCard(card: AgentCard): Promise<void> {
      // Validate AgentCard schema
      const result = AgentCardSchema.safeParse(card);
      if (!result.success) {
        this.logger.error(`Invalid AgentCard format:`, result.error);
        throw new Error(`Invalid AgentCard format: ${result.error.message}`);
      }

      // Validation for uniqueness of ID is assumed here (may be implemented in the caller)
      this.agentCards.set(card.id, card);
      this.logger.log(`AgentCard added or updated for ${card.id}`);
      // TODO: Persist to file system or DB if needed. This is a good place to consider that logic.
    }

    validateTrigger(triggerData: any, inputSchema: any): boolean {
      if (!inputSchema) {
        // No schema, validation passes by default
        return true;
      }

      try {
        if (typeof inputSchema === "object" && inputSchema !== null && typeof inputSchema.parse === 'function'){
          // Assume inputSchema is a Zod Schema
          inputSchema.parse(triggerData);
        }
        else {
          const schema:ZodSchema = z.any();
          schema.parse(triggerData)
        }
        return true;
      } catch (error) {
        this.logger.error("Trigger data validation error:", error);
        return false;
      }
    }
