        //TODO - make this more dynamic
        this.platformHandlers.set('claude_desktop', {}); // Impl me - new ClaudeDesktopTriggerHandler());
        this.platformHandlers.set('vscode_copilot', {}); // Impl me - new VSCodeCopilotTriggerHandler());
        this.platformHandlers.set('chrome_ai', {}); // Impl me - new ChromeAIPlatformTriggerHandler());
        this.platformHandlers.set('web_ai', {}); // Impl me - new WebAIPlatformTriggerHandler());

        // Initialize cron job manager
        this.cronJobManager = new CronJobManager(this, this.redisStreams);

        // Initialize heartbeat service
        this.heartbeatService = new AgentHeartbeatService(this, this.redisStreams);

        // Subscribe to Redis Streams for orchestration events
        await this.subscribeToOrchestrationEvents();

        this.logger.log('Universal Trigger Service initialized');
    }

    // Main trigger function - called by Director/Broker
    async triggerAgent(agentId: string, trigger: TriggerRequest): Promise<TriggerResult> {
        try {
            const agent = await this.mcpBroker.getAgent(agentId);
            if (!agent) {
                // Re-throw for specific handling
                throw {
                    code: TriggerErrorCode.AGENT_NOT_FOUND,
                    message: `Agent not found: ${agentId}`,
                    context: { agentId }
                };
            }

            const handler = this.platformHandlers.get(agent.platform);
            if (!handler) {
                return this.createErrorResult(TriggerErrorCode.HANDLER_NOT_FOUND, `No handler found for platform: ${agent.platform}`, { agentId, platform: agent.platform });
            }
            const parsedTrigger = TriggerRequestSchema.safeParse(trigger);
            if (!parsedTrigger.success) {
                return this.createErrorResult(TriggerErrorCode.ZOD_VALIDATION_FAILED, `Invalid TriggerRequest: ${parsedTrigger.error.message}`, { 
                        agentId, 
                        trigger, 
                        zodValidationError: parsedTrigger.error.errors
                });
            }
            const agentCard = await this.agentInfoService.getAgentCard(agentId);
            if (!agentCard) {
                return this.createErrorResult(TriggerErrorCode.AGENT_CARD_VALIDATION_FAILED, `AgentCard not found for agent: ${agentId}`, {agentId});
            }
            try {
              if (!this.validateTrigger(parsedTrigger.data, agentCard.capabilities?.inputSchema)) {
                  return this.createErrorResult(TriggerErrorCode.VALIDATION_ERROR, `Invalid trigger for agent ${agentId}: Trigger does not conform to AgentCard.`, { agentId, trigger, agentCardCapabilities: agentCard.capabilities});
              }
            }
            catch(e) {
              return this.createErrorResult(TriggerErrorCode.AGENT_CARD_VALIDATION_FAILED, `AgentCard validation error: ${e.message}`, {agentId, trigger, agentCard });
            }

            let encryptedMessage;
            try {
                encryptedMessage = encryptMessage(trigger.message);
            } catch (encryptionError) {
                return this.createErrorResult(TriggerErrorCode.ENCRYPTION_ERROR, `Error encrypting message: ${encryptionError.message}`, { agentId, trigger, encryptionError });
            }

            const encryptedTrigger = { ...trigger, message: encryptedMessage };
            let result;
            try {
                result = await handler.executeTrigger(agent, encryptedTrigger);
            }
            catch(handlerError){
                return this.createErrorResult(TriggerErrorCode.TRIGGER_EXECUTION_FAILED, `Trigger execution failed on platform handler: ${handlerError.message}`, {
                    agentId,
                    trigger,
                    platform: agent.platform,
                    handlerError
                });
            }
            // Decrypt the result (if needed)
            if (result.data) {
                try{
                    result.data = decryptMessage(result.data);
                }
                catch(decryptionError) {
                  this.logger.error(`Decryption failed for agent ${agentId}:`, decryptionError);
                }
            }

            // Log trigger execution
            await this.logTriggerExecution(agentId, trigger, result);

            // Publish result to Redis Streams
            await this.redisStreams.publish('trigger-results', {
                agentId,
                trigger,
                result,
                timestamp: Date.now()
            });

            return result;

        }
        catch (error:any) {
            if (isTriggerError(error)) {
                this.logger.error(`Trigger execution failed with structured error:`, error);
                throw error; // Re-throw structured errors for higher-level handling
            }
            this.logger.error(`Trigger execution failed with unexpected error for agent ${agentId}:`, error);
            return {
                success: false,
                error: {
                    code: TriggerErrorCode.TRIGGER_EXECUTION_FAILED,
                    message: `Unexpected error: ${error.message || error}`,
                    context: { agentId, trigger, stackTrace: error.stack }
                },
                timestamp: Date.now()
            };
        }
    }
    private async logTriggerExecution(agentId: string, trigger: TriggerRequest, result: TriggerResult): Promise<void> {
      const logData = {
        agentId,
        triggerType: trigger.type,
        triggerPriority: trigger.priority,
        message: trigger.message,
        success: result.success,
        timestamp: result.timestamp
      };

      if (result.error) {
        this.logger.error(`Agent trigger event ${agentId} : ${trigger.type} failure.`, logData);
      } else {
        this.logger.log(`Agent trigger event ${agentId} : ${trigger.type} success.`, logData);
      }
    }
    // Function call interfaces for The New Fuse workflows
    // TODO - add security validation on direct calls
    async handleTriggerAgent(data: { agentId: string; message: string }): Promise<TriggerResult> {
        return await this.triggerAgent(data.agentId, {
            type: 'manual',
            message: data.message,
            priority: 'medium'
        });
    }
        async handleStartHeartbeat(data: { agentId: string; interval: number; message?: string }): Promise<void> {
        await this.heartbeatService.startHeartbeat(data.agentId, {
