        async handleScheduleTrigger(data: ScheduleTriggerRequest): Promise<void> {
        await this.cronJobManager.schedule(
            data.agentId,
            data.schedule,
            data.trigger
        );
    }

    // Integration with Director for workflow orchestration
        async setupWorkflowTriggers(workflow: WorkflowDefinition): Promise<void> {
        for (const step of workflow.steps) {
            if (step.triggers) {
                for (const trigger of step.triggers) {
                    await this.cronJobManager.schedule(
