// src/redis/redis-streams.service.ts
import { Injectable, Inject, Logger } from '@nestjs/common';
import { Redis } from 'ioredis';
import { RedisConsumerGroupConfig } from 'src/types/RedisConsumerGroup';

@Injectable()
export class RedisStreamsService {
    private readonly redisClient: Redis;
    private readonly logger = new Logger(RedisStreamsService.name);
    constructor(
        @Inject('REDIS_CLIENT') private redis: Redis,
        @Inject('LOGGER') private loggerService: Logger
    ) {
        this.redisClient = redis;
    }

    async publish(stream: string, data: any): Promise<void> {
        try {
            await this.redisClient.xadd(stream, '*', ...this.objectToKeyValueArray(data));
            this.loggerService.log(`Published event to stream ${stream}: ${JSON.stringify(data)}`);
        } catch (error) {
            this.loggerService.error(`Failed to publish event to stream ${stream}:`, error);
        }
    }

    async subscribeToGroup(stream: string, config: RedisConsumerGroupConfig, handler: (message: any) => void): Promise<void> {
      const { groupName, consumerName, blockMs = 1000, count = 1 } = config;

      try {
        // Attempt to create the consumer group if it does not exist
        await this.redisClient.xgroup('CREATE', stream, groupName, '$', 'MKSTREAM');
        this.loggerService.log(`Consumer group "${groupName}" created for stream "${stream}"`);
      } catch (error: any) {
        // Ignore BUSYGROUP error which indicates the group already exists
        if (error.message !== 'BUSYGROUP Consumer Group name already exists') {
          this.loggerService.error(`Error creating consumer group "${groupName}" for stream "${stream}":`, error);
        }
      }

      let lastId = '>'; // Start reading only new entries

      while (true) {
        try {
          const response = await this.redisClient.xreadgroup('GROUP', groupName, consumerName, 'COUNT', count, 'BLOCK', blockMs, 'STREAMS', stream, lastId);

          if (response) {
            const [streamData] = response;
            const [_, messages] = streamData;

            for (const message of messages) {
              const messageId = message[0];
              const messageData = this.keyValueArrayToObject(message[1]);

              try {
                await handler(messageData);
                await this.redisClient.xack(stream, groupName, messageId); // Acknowledge message processing
              } catch (handlerError) {
                this.loggerService.error(`Error processing message ${messageId} from stream ${stream} in group ${groupName}:`, handlerError);
                // Consider DLQ pattern or retry mechanism here if message processing fails
              }
              lastId = messageId;
            }
          }
        } catch (error) {
          this.loggerService.error(`Error reading from stream "${stream}" in group "${groupName}":`, error);
          await new Promise(resolve => setTimeout(resolve, 5000)); // Simple retry backoff
        }
      }
    }
    async subscribe(stream: string, handler: (message: any) => void): Promise<void> {
    const config: RedisConsumerGroupConfig = {
      groupName: 'default-group',
      consumerName: `consumer-${Date.now()}`, // Unique consumer name
    };
    await this.subscribeToGroup(stream, config, handler);
  }
     async trimStream(stream: string, maxLength: number): Promise<void> {
        try {
            await this.redisClient.xtrim(stream, 'MAXLEN', '~', maxLength);
            this.loggerService.log(`Trimmed stream ${stream} to a maximum length of ${maxLength}`);
        } catch (error) {
            this.loggerService.error(`Failed to trim stream ${stream}:`, error);
        }
    }
  private objectToKeyValueArray(obj: any): string[] {
    const keyValueArray: string[] = [];
    for (const key in obj) {
      if (Object.hasOwn(obj, key)) {
        keyValueArray.push(key, obj[key] === null ? null : typeof obj[key] === 'object' ? JSON.stringify(obj[key]) : String(obj[key]));
      }
    }
    return keyValueArray;
  }

  private keyValueArrayToObject(arr: string[]): Record<string, any> {
    const obj: Record<string, any> = {};
    for (let i = 0; i < arr.length; i += 2) {
      const key = arr[i];
      let value: any = arr[i + 1];
      try {
          value = JSON.parse(value);
      } catch (e) {
          // If it's not JSON, keep the value as is
      }
      obj[key] = value;
    }
    return obj;
  }
}
