@Injectable()
export class MetricsAggregatorService implements OnModuleInit {
    private readonly systemEventsStream = 'agent-system-events';
    constructor(
        private redisStreamsService: RedisStreamsService,
        private prometheusService: PrometheusService,
        @Inject('LOGGER') private logger: Logger,
    ) { }
    private workflowCompletionsCounter = this.prometheusService.createCounter(
        'workflow_completions_total',
        'Total number of workflow completions',
        ['status']
    );
    private triggerFailuresCounter = this.prometheusService.createCounter(
        'trigger_failures_total',
        'Total number of trigger failures',
        ['agentId', 'code', 'errorType']
    );

    private stepCompletionsCounter = this.prometheusService.createCounter(
        'step_completions_total',
        'Total number of step completions',
        ['status']
    );
    private stepLatencyHistogram = this.prometheusService.createHistogram(
        'step_execution_latency_seconds',
        'Step execution latency in seconds',
        ['agentId', 'stepId'],
        [0.1, 0.5, 1, 5, 10, 30, 60] // Buckets for latency distribution (seconds)
    );
    async onModuleInit() {
        await this.subscribeToEvents();
    }

    private async subscribeToEvents(): Promise<void> {
        await this.redisStreamsService.subscribe('workflow-events', async (event) => {
            this.handleWorkflowCompletedEvent(event);
        });
        await this.redisStreamsService.subscribe('trigger-results', async (event) => {
            if (!event.result.success) {
                this.handleTriggerFailedEvent(event);
            }

        });
         await this.redisStreamsService.subscribe('workflow-step-events', async (event) => {
            if (event.type === 'step_completed') {
              this.handleStepCompletedEvent(event.data)
            }
          })

        this.logger.log('Metrics Aggregator Service initialized and subscribed to events');
    }

    private handleWorkflowCompletedEvent(workflow: any): void {
        this.workflowCompletionsCounter.inc({ status: workflow.status }, 1);
        this.publishSystemEvent('workflow_completed', 'metrics-aggregator', workflow); // Publish system event

        this.logger.log(`Workflow completed: ${workflow.id} with status ${workflow.status}`);
    }

    private handleTriggerFailedEvent(event: any): void {
        if (isTriggerError(event.result.error)) {
            this.triggerFailuresCounter.inc(
                { agentId: event.agentId, code: event.result.error.code, errorType: this.getErrorType(event.result.error.code) },
                1
            );
          this.publishSystemEvent('trigger_failed', 'metrics-aggregator', { agentId: event.agentId, code: event.result.error.code, errorType: this.getErrorType(event.result.error.code) , message: event.result.error.message }); // Publish system event
            this.logger.warn(`Trigger failed for agent ${event.agentId} with code ${event.result.error.code}: ${event.result.error.message}`);
        } else {
            this.logger.error('Unstructured trigger error found in events', event)
        }
    }
private publishSystemEvent(type: string, source: string, data: any): void {
        const systemEvent: SystemEvent = {
            type,
            source,
            timestamp: Date.now(),
            data,
        };
        this.redisStreamsService.publish(this.systemEventsStream, systemEvent)
            .catch(e => this.logger.error(`Error publishing to ${this.systemEventsStream}`, e));
    }
    private handleStepCompletedEvent(event: any): void {
      // Extract latency information (example)
      if (event.startTime && event.endTime) {
        const latencySeconds = (event.endTime - event.startTime) / 1000;
        this.stepLatencyHistogram.observe({ agentId: event.agentId, stepId: event.stepId }, latencySeconds);
      }
      this.stepCompletionsCounter.inc({status: event.status ?? "completed"});
      this.publishSystemEvent('step_completed', 'metrics-aggregator', event); // Publish system event
      this.logger.log(`Completed Step for agent : ${event.agentId}  and stepId ${event.stepId} `)
    }
    private getErrorType(code: number): string {
