// src/director/director.service.ts
import { Injectable, Inject, Logger } from '@nestjs/common';
import { MCPBrokerService } from '../mcp/mcp-broker.service';
import { UniversalTriggerService } from '../services/UniversalTriggerService';
import { TriggerError, TriggerErrorCode, isTriggerError } from '../types/TriggerError';
import { CronSchedule, TriggerRequest } from '../types/TriggerRequest';
import { WorkflowDefinition, WorkflowStep, WorkflowResult } from '../types/Workflow';
import { RedisStreamsService } from '../redis/redis-streams.service';

interface WorkflowStepStatus {
    status: 'pending' | 'running' | 'succeeded' | 'failed' | 'skipped';
    result?: any;
    error?: any; // For simpler integration here, not enforcing the most explicit definition - to align with the existing flow
    retries?: number;
}

@Injectable()
export class DirectorService {
    private activeWorkflows: Map<string, WorkflowResult> = new Map();
    private stepStatuses: Map<string, WorkflowStepStatus> = new Map(); // Key: workflowId-stepId
    private readonly maxRetries = 3; // Configurable max retries

    constructor(
        @Inject('MCP_BROKER') private mcpBroker: MCPBrokerService,
        private triggerService: UniversalTriggerService,
        @Inject('LOGGER') private logger: Logger,
        private redisStreams: RedisStreamsService
    ) { }

    async executeWorkflow(workflow: WorkflowDefinition): Promise<WorkflowResult> {
        const workflowId = this.generateWorkflowId(); // Generate a unique ID
        const workflowResult: WorkflowResult = {
            id: workflowId,
            workflowDefinition: workflow,
            status: 'running',
            startTime: Date.now(),
            endTime: null,
            steps: workflow.steps.map(step => ({ ...step, status: 'pending' })) // Initialize step statuses
        };

        this.activeWorkflows.set(workflowId, workflowResult);

        try {
            // Initialize step statuses
            workflow.steps.forEach(step => {
                this.stepStatuses.set(`${workflowId}-${step.id}`, { status: 'pending', retries: 0 });
            });

            await this.executeWorkflowSteps(workflowResult);
            workflowResult.status = 'succeeded';
            workflowResult.endTime = Date.now();
        } catch (error) {
            workflowResult.status = 'failed';
            workflowResult.endTime = Date.now();
            this.logger.error(`Workflow ${workflowId} failed:`, error);
        } finally {
            this.activeWorkflows.delete(workflowId);
            // Publish workflow completion event
            await this.publishWorkflowEvent('workflow_completed', workflowResult);
        }

        return workflowResult;
    }
    private async executeWorkflowSteps(workflowResult: WorkflowResult): Promise<void> {
        const workflowId = workflowResult.id;
        for (const step of workflowResult.workflowDefinition.steps) {
            const stepStatusKey = `${workflowId}-${step.id}`;
            const stepStatus = this.stepStatuses.get(stepStatusKey);

            try {
                if (stepStatus.status === 'skipped') {
                    this.logger.log(`Skipping step ${step.id} in workflow ${workflowId}`);
                    continue;
                }
                this.stepStatuses.set(stepStatusKey, { ...stepStatus, status: 'running' });
                this.logger.log(`Executing step ${step.id} in workflow ${workflowId}`);
                const result = await this.triggerService.triggerAgent(step.agentId, step.trigger);
                this.stepStatuses.set(stepStatusKey, { ...stepStatus, status: 'succeeded', result });
                await this.publishWorkflowStepEvent("step_completed", step.agentId, step.id,  Date.now(), result)

            } catch (error) {
                if (isTriggerError(error)) {
                    const retryCount = stepStatus.retries || 0;

                    if (error.code === TriggerErrorCode.AGENT_NOT_FOUND) {
                        this.logger.error(`Workflow ${workflowId}, step ${step.id} - Agent not found, skipping retries.`, error);
                        this.stepStatuses.set(stepStatusKey, { status: 'failed', error: this.formatError(error), retries: retryCount + 1 }); // Simplest version - this sets up for later retry loops
                        break;
                    }
                    else if (retryCount < this.maxRetries && this.isTransientError(error.code)) {
                        // Implement retry with exponential backoff
                        const delay = this.calculateBackoffDelay(retryCount);
                        this.logger.warn(`Workflow ${workflowId}, step ${step.id} - Transient error, retrying in ${delay}ms (attempt ${retryCount + 1}/${this.maxRetries}):`, error);
                        await this.delay(delay);
                        this.stepStatuses.set(stepStatusKey, { ...stepStatus, status: 'pending', retries: retryCount + 1 });
                        // How to retry from same spot without recursive call stack overflow concerns:
                        continue // or simply a `return executeWorkflowSteps(workflowResult)` which could lead to stack issues at depth
                    }
                    else {
                        this.logger.error(`Workflow ${workflowId}, step ${step.id} - Trigger failed after retries:`, error);
                        this.stepStatuses.set(stepStatusKey, { status: 'failed', error: this.formatError(error), retries: retryCount + 1 }); // Simplest version - this sets up for later retry loops
                        break;
                    }
                }
                else {
                    this.logger.error(`Workflow ${workflowId}, step ${step.id} - Unexpected error:`, error);
                    this.stepStatuses.set(stepStatusKey, { status: 'failed', error: this.formatError(error), retries: (stepStatus.retries || 0) + 1 });
                    break;
                }
            }
        }
    }

    // Simple helpers - can factor into Util class
    private generateWorkflowId(): string {
        return `workflow-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    }

    private calculateBackoffDelay(retryCount: number): number {
        const baseDelay = 1000; // 1 second
        return baseDelay * Math.pow(2, retryCount);
    }

    private delay(ms: number): Promise<void> {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    private isTransientError(code: TriggerErrorCode): boolean {
        // Define which error codes are considered transient (e.g., temporary network issues)
        return [TriggerErrorCode.TRIGGER_EXECUTION_FAILED].includes(code);
    }

    private formatError(error: any): any {
        if (isTriggerError(error)) {
            return {
                errorId: `error-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
                errorCode: error.code,
                errorMessage: error.message,
                errorType: this.getErrorType(error.code),
                timestamp: Date.now(),
                // Include more context, agentId, trigger, and so on from error.context if required
                ...error.context // Spread in the context
            };
        }
        // For non-TriggerError objects, return minimal detail
        return {
            errorId: `error-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            errorCode: -1, // Unknown error code
            errorMessage: error.message || String(error),
            errorType: 'unexpected',
            timestamp: Date.now()
        };
    }
    private getErrorType(code: TriggerErrorCode): string {
        switch (code) {
            case TriggerErrorCode.AGENT_NOT_FOUND:
            case TriggerErrorCode.HANDLER_NOT_FOUND:
                return 'configuration';
            case TriggerErrorCode.VALIDATION_ERROR:
            case TriggerErrorCode.AGENT_CARD_VALIDATION_FAILED:
            case TriggerErrorCode.ZOD_VALIDATION_FAILED:
                return 'validation';
            case TriggerErrorCode.TRIGGER_EXECUTION_FAILED:
                return 'execution';
            default:
                return 'unknown';
        }
    }

    private async publishWorkflowEvent(eventType: string, data: any): Promise<void> {
        await this.redisStreams.publish('workflow-events', { type: eventType, data, timestamp: Date.now() });
    }
        private async publishWorkflowStepEvent(eventType: string, agentId : string, stepId : string, endTime : number, result : any): Promise<void> {
          const data = {
            agentId,
            stepId,
            endTime,
            status: result?.success ? 'completed' : 'failed',
            startTime: Date.now() - 120, //Fake a start time (improve)
            triggerDetails: result?.trigger
          }
        await this.redisStreams.publish('workflow-step-events', { type: eventType, data, timestamp: Date.now() });
    }
}
